        semantic_config: Option<EncoderSpec>,
        payload: CachedIndexPayload,
        cache_entry: Option<CacheEntry>,
        context: Option<CacheContext>,
        signature_context: Option<SourceSignatureContext>,
    ) -> Result<Self> {
        if payload.chunks.is_empty() {
