fn build_index_for_mode(
    path: &str,
    ref_name: Option<&str>,
    mode: SearchMode,
    encoder_spec: EncoderSpec,
    cache: CacheConfig,
    offline: bool,
    include_docs: bool,
    extensions: Option<std::collections::HashSet<String>>,
) -> Result<SifsIndex> {
    match mode {
        SearchMode::Bm25 => {
            build_sparse_index(path, ref_name, cache, offline, include_docs, extensions)
        }
        SearchMode::Semantic | SearchMode::Hybrid => build_hybrid_index(
            path,
            ref_name,
            encoder_spec,
            cache,
            offline,
            include_docs,
            extensions,
        ),
    }
}

fn build_sparse_index(
    path: &str,
    ref_name: Option<&str>,
    cache: CacheConfig,
    offline: bool,
    include_docs: bool,
    extensions: Option<std::collections::HashSet<String>>,
) -> Result<SifsIndex> {
    let options = IndexOptions::sparse()
        .with_cache(cache)
        .with_include_text_files(include_docs)
        .with_extensions(extensions);
    if is_git_url(path) {
        if offline {
            bail!("--offline does not allow remote Git sources");
        }
        SifsIndex::from_git_with_index_options(path, ref_name, options)
    } else {
        SifsIndex::from_path_with_index_options(path, options)
    }
}

